44→        </div>
45→
46→        {error && <div className="login-error">{error}</div>}
47→
48→        <div className="login-field">
49→          <label>Foydalanuvchi</label>
50→          <input 
51→            type="text" 
52→            placeholder="Login kiriting"
53→            value={username} 
54→            onChange={(e) => setUsername(e.target.value)} 
55→            required 
56→            autoFocus
57→          />
58→        </div>
59→
60→        <div className="login-field">
61→          <label>Parol</label>
62→          <input 
63→            type="password" 
64→            placeholder="Parol kiriting"
65→            value={password} 
66→            onChange={(e) => setPassword(e.target.value)} 
67→            required 
68→          />
69→        </div>
70→
71→        <button type="submit" className="btn-submit login-btn" disabled={loading}>
72→          {loading ? 'Kutilmoqda...' : 'Kirish'}
73→        </button>
74→      </form>
75→    </div>
76→  );
77→};
